module RefModule(
    input clk,
    input rst,
    output reg [2:0] q
);
    reg [2:0] unused_count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            unused_count <= 3'b000;
            q <= 3'b000;
        end else begin
            if (unused_count == 3'b111) begin
                unused_count <= 3'b000;
                q <= q + 1;
            end else begin
                unused_count <= unused_count + 1;
            end
        end
    end
endmodule
